mapper.select:
SELECT id, userNm, eml, mtelno, gndrSe, userSe, userStsSe FROM ( SELECT INNER_Q.*, ROWNUM AS RN FROM ( SELECT id, userNm, eml, mtelno, gndrSe, userSe, userStsSe FROM ( SELECT USER_ID AS id , USER_NM AS userNm , EML AS eml , MTELNO AS mtelno , GNDR_SE AS gndrSe , 'A' AS userSe , ADM_STS_SE AS userStsSe FROM CMS_USER_ADMIN UNION ALL SELECT USER_ID AS id , USER_NM AS userNm , EML AS eml , MTELNO AS mtelno , GNDR_SE AS gndrSe , 'E' AS userSe , USER_STS_SE AS userStsSe FROM CMS_USER_TASK UNION ALL SELECT USER_ID AS id , USER_NM AS userNm , EML AS eml , MTELNO AS mtelno , GNDR_SE AS gndrSe , 'G' AS userSe , USER_STS_SE AS userStsSe FROM CMS_USER )
AND userSe = #{userSe}
ORDER BY userSe, userNm ) INNER_Q ) WHERE RN > #{offset} AND RN <= #{offset} + #{size}

mapper.insert:
