INSERT INTO CMS_USER (
    USER_ID
  , USER_NM
  , MTELNO
  , TELNO
  , GNDR_SE
  , EML
  , ADDR
  , DADDR
  , ZIP
  , USER_STS_SE
  , EML_CERT_YN
  , TELNO_CERT_YN
  , 
) VALUES (
    #{userId}
  , #{userNm}
  , #{mtelno}
  , #{telno}
  , #{gndrSe}
  , #{eml}
  , #{addr}
  , #{daddr}
  , #{zip}
  , #{userStsSe}
  , #{emlCertYn}
  , #{telnoCertYn}
  , 
)

INSERT INTO CMS_PWD (
    USER_ID
  , USER_SE
  , PWD
  , USE_YN
  , 
) VALUES (
    #{userId}
  , #{userSe}
  , #{pwd}
  , #{useYn}
  , 
)

INSERT INTO CMS_PWD_HIST (
    SN
  , PWD
  , USER_SE
  , PWD_CHG_YMD
  , CHG_USER_ID
  , CHG_USER_SE
  , 
) VALUES (
    (SELECT NVL(MAX(SN), 0) + 1 FROM CMS_PWD_HIST)
  , #{pwd}
  , #{userSe}
  , #{pwdChgYmd}
  , #{chgUserId}
  , #{chgUserSe}
  , 
)

mapper.update:
UPDATE CMS_USER_ADMIN
   SET USER_NM  = #{vo.userNm}
     , EML      = #{vo.eml}
     , MTELNO   = #{vo.mtelno}
     , GNDR_SE  = #{vo.gndrSe}
     , TELNO    = #{vo.telno}
     , ADDR     = #{vo.addr}
     , DADDR    = #{vo.daddr}
     , 
 WHERE USER_ID  = #{userId}

UPDATE CMS_USER_TASK
   SET USER_NM  = #{vo.userNm}
     , EML      = #{vo.eml}
     , MTELNO   = #{vo.mtelno}
     , GNDR_SE  = #{vo.gndrSe}
     , TELNO    = #{vo.telno}
     , ADDR     = #{vo.addr}
     , DADDR    = #{vo.daddr}
     , 
 WHERE USER_ID  = #{userId}

UPDATE CMS_USER
   SET USER_NM  = #{vo.userNm}
     , EML      = #{vo.eml}
     , MTELNO   = #{vo.mtelno}
     , GNDR_SE  = #{vo.gndrSe}
     , TELNO    = #{vo.telno}
     , ADDR     = #{vo.addr}
     , DADDR    = #{vo.daddr}
     , ZIP      = #{vo.zip}
     , 
 WHERE USER_ID  = #{userId}

UPDATE CMS_PWD
   SET PWD     = #{pwd}
     , 
 WHERE USER_ID = #{userId}
   AND USER_SE = #{userSe}

mapper.delete:
DELETE FROM CMS_PWD
 WHERE USER_ID = #{userId}
   AND USER_SE = #{userSe}
